49	void sendChildInfoGeneric(childInfoType info_type, size_t keys, double progress, char *pname) {
50	    if (server.child_info_pipe[1] == -1) return;
51	
52	    static monotime cow_updated = 0;
53	    static uint64_t cow_update_cost = 0;
54	    static size_t cow = 0;
55	    static size_t peak_cow = 0;
56	    static size_t update_count = 0;
57	    static unsigned long long sum_cow = 0;
58	
59	    child_info_data data = {0}; /* zero everything, including padding to satisfy valgrind */
60	
61	    /* When called to report current info, we need to throttle down CoW updates as they
62	     * can be very expensive. To do that, we measure the time it takes to get a reading
63	     * and schedule the next reading to happen not before time*CHILD_COW_COST_FACTOR
64	     * passes. */
65	
66	    monotime now = getMonotonicUs();
67	    if (info_type != CHILD_INFO_TYPE_CURRENT_INFO ||
68	        !cow_updated ||
69	        now - cow_updated > cow_update_cost * CHILD_COW_DUTY_CYCLE)
70	    {
71	        cow = zmalloc_get_private_dirty(-1);
72	        cow_updated = getMonotonicUs();
73	        cow_update_cost = cow_updated - now;
74	        if (cow > peak_cow) peak_cow = cow;
75	        sum_cow += cow;
76	        update_count++;
77	
78	        int cow_info = (info_type != CHILD_INFO_TYPE_CURRENT_INFO);
79	        if (cow || cow_info) {
80	            serverLog(cow_info ? LL_NOTICE : LL_VERBOSE,
81	                      "Fork CoW for %s: current %zu MB, peak %zu MB, average %llu MB",
82	                      pname, cow>>20, peak_cow>>20, (sum_cow/update_count)>>20);
83	        }
84	    }
85	
86	    data.information_type = info_type;
87	    data.keys = keys;
88	    data.cow = cow;
89	    data.cow_updated = cow_updated;
90	    data.progress = progress;
91	
92	    ssize_t wlen = sizeof(data);
93	
94	    if (write(server.child_info_pipe[1], &data, wlen) != wlen) {
95	        /* Failed writing to parent, it could have been killed, exit. */
96	        serverLog(LL_WARNING,"Child failed reporting info to parent, exiting. %s", strerror(errno));
97	        exitFromChild(1, 0);
